var module_75014877291=function(){$(".accordion-row").on("click",(function(){const target="#"+$(this).data("target");$(target).hasClass("active")?$(this).removeClass("active"):$(this).addClass("active")}));const setWidth=element=>{const widths=$(element).map((function(){return $(this).width()})).get(),maxWidth=Math.max.apply(null,widths);$(element).map((function(){$(this).width(maxWidth)}))};window.addEventListener("DOMContentLoaded",(()=>{setWidth(".token-name"),setWidth(".total-supply");let numDynamic=0;$(".dynamic-details").each((function(){const curRow=parseInt($(this).data("row"));curRow>numDynamic&&(numDynamic=curRow)}));for(let i=0;i<=numDynamic;i++)setWidth(`.dynamic-details[data-row='${i}']`)}))}();